// Score each contact 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.email) score += 20;
  if (j.company) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});

// Build a stable idempotency key per contact (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.contactId, j.email].join('|')) } };
});
